public protocol BrowserSimCoreProtocol : AnyObject {
    
    /**
     * Abort the in-flight `capture_video` — the explicit-abort design (the
     * Stage-0 finding: a dropped future's `Drop` cannot run the async
     * abort+drain). Sends `capture_video_abort`, then a bounded drain: if the
     * browser does not emit the partial `video_result` within
     * `VIDEO_DRAIN_TIMEOUT_MS`, force-resolves the pending op so the in-flight
     * `capture_video` returns rather than waiting the full op timeout.
     *
     * **F18 (iteration-3 root cause + fix):** the original implementation
     * slept `VIDEO_DRAIN_TIMEOUT_MS` UNCONDITIONALLY and only checked at
     * the end. If `video_result` arrived during the sleep, it landed in
     * `complete_pending` which removed the sender and delivered the value
     * — the post-sleep `remove` was a no-op (sender already gone). Normal
     * case worked fine.
     *
     * But if `video_result` arrived AFTER the sleep ended (e.g. an 8MB+
     * frame traversing OkHttp on a slow network — observed 6s delivery
     * delay in iteration-3 dogfood, frame arrived at T+10.083s while
     * sleep ended at T+10.000s), abort had already force-resolved
     * `pending` with `{"type":"aborted"}`. `complete_pending` then ran
     * for the late `video_result`, found no sender, and logged the
     * well-named "duplicate or post-timeout response — ignoring" before
     * dropping it on the floor.
     *
     * Fix: replace the unconditional sleep with a poll loop that exits
     * early when the pending sender is removed (signal that
     * `complete_pending` consumed the `video_result` and delivered it).
     * Bump the max wait so large frames have headroom.
     */
    func abortCaptureVideo() async 
    
    /**
     * Cancel the currently-speaking utterance — fire-and-forget.
     */
    func cancelSpeak() 
    
    /**
     * Capture a still photo through the browser surrogate.
     */
    func capturePhoto(resolution: Resolution, format: PhotoFormat, dedicatedCapture: Bool) async  -> CapturePhotoResult
    
    /**
     * Capture a video clip through the browser surrogate.
     */
    func captureVideo(maxDurationSeconds: Int32?, includeAudio: Bool, format: VideoFormat) async  -> CaptureVideoResult
    
    /**
     * Open the simulator session. `mcp_install_id` is the shell's MCP
     * `/whoami` probe result (the probe stays shell-side — the core does no
     * network). Returns `None` on success, `Some(ConnectError)` on failure.
     */
    func connect(mcpInstallId: String?) async  -> ConnectError?
    
    /**
     * The currently-bound session URL, if any. The shell mirrors this for
     * its `currentSessionUrl()` getter.
     */
    func currentSessionUrl()  -> String?
    
    /**
     * The session's current device model id (identity dial,
     * device-capability-model.md) — `None` until the handshake delivers it.
     * Backs the shell's `GlassesTransport.currentDeviceModelId()`.
     */
    func deviceModelId()  -> String?
    
    /**
     * End the session at the customer's request.
     */
    func disconnect() 
    
    /**
     * Play a short non-speech earcon — fire-and-forget.
     */
    func earcon(sound: EarconSound, volume: Float) 
    
    /**
