     * temple tap produces on real glasses.
     */
    func isCameraPaused()  -> Bool
    
    /**
     * An inbound binary frame — the payload of the preceding meta frame.
     */
    func onBinary(bytes: Data) 
    
    /**
     * The socket closed (`code` is the WebSocket close code). A non-clean
     * closure (anything but 1000) drives the reconnect loop.
     */
