/**
 * Durable asset-key → hosted-copy registry, shared by video AND photo
 * (DSP-29). Pure synchronous state behind one `Mutex` (mirrors `VoiceCore`); no
 * IO and no async cross the FFI here — the shell drives the network and the
 * persistence. `BTreeMap` keeps the snapshot deterministic so an unchanged
 * registry serializes byte-identically.
 */
public protocol HostedMediaRegistryProtocol : AnyObject {
    
    /**
     * Drop `key`'s hosted copy and hand back its delete handle so the shell can
     * `DELETE` the backend object. `None` if nothing was on record — forgetting
     * an unhosted asset is a no-op (idempotent), so a source deleted before it
     * was ever displayed costs nothing.
     */
    func forget(key: String)  -> HostedAsset?
    
    /**
     * The hosted copy on record for `key`, or `None` (a miss → the shell must
     * upload). The DSP-24 dedup read; a hit means no re-upload.
     */
    func lookup(key: String)  -> HostedAsset?
    
    /**
     * Record the hosted copy after a successful upload — retaining the delete
     * handle (DSP-23). Only called on a lookup miss, so the slot is empty.
     */
    func record(key: String, hosted: HostedAsset) 
    
    /**
     * Serialize the whole registry for the shell to persist. Deterministic
     * (`BTreeMap` ordering); `{}` on the impossible serialize failure.
     */
    func snapshotJson()  -> String
    
}

