/**
 * The migrated RealMeta orchestration core. One per shell `RealMetaTransport`.
 */
public protocol RealMetaCoreProtocol : AnyObject {
    
    /**
     * Explicit abort for an in-flight `capture_video` — mirrors
     * `BrowserSimCore::abort_capture_video`. The bridge resolves the pending
     * op (with a partial clip or an error) via `on_video_captured`.
     */
    func abortCaptureVideo() async 
    
    /**
     * Cancel the currently-speaking utterance — fire-and-forget. The bridge
     * stops its TTS engine; the in-flight `speak` future resolves on the
     * bridge's `on_speak_completed` (with or without an error depending on
     * the platform).
     */
    func cancelSpeak() 
    
    func capturePhoto(resolution: Resolution, format: PhotoFormat, dedicatedCapture: Bool) async  -> RealMetaCapturePhotoResult
    
    func captureVideo(maxDurationSeconds: Int32?, includeAudio: Bool, format: VideoFormat, resolution: Resolution, frameRate: Int32) async  -> RealMetaCaptureVideoResult
    
    /**
     * The full connect orchestration. Walks: SDK init → registration →
     * create device session → start device session. Returns `Some(error)` on
     * failure; `None` on success (the actual `Active` transition arrives via
     * the device-state observer once the SDK reports it).
     */
    func connect(deviceId: String?) async  -> ConnectError?
    
    /**
     * Connect body. `auto_reload = true` (the normal entry) appends ONE automatic
     * disconnect + reconnect after the fresh connect establishes. On a reopened app
     * Meta's camera photo path is broken after a first connect (`capturePhoto` times
     * out); the disconnect clears the stale glasses-side session left by the previous
     * process and the reconnect re-registers on the cleared state — `capturePhoto` then
     * works reliably. This is exactly the user's manual "reload once", done automatically.
     * The recursive reconnect passes `auto_reload = false` to stop.
     */
    func connectInternal(deviceId: String?, autoReload: Bool) async  -> ConnectError?
    
    func disconnect() async 
    
    /**
     * Play a short earcon — fire-and-forget.
     */
    func earcon(sound: EarconSound, volume: Float) 
    
    /**
     * Gap 1 self-heal: bring up the device (capture) session reliably. Waits
     * until the link is actually CONNECTED — firing `create_device_session`
     * while it is still CONNECTING is the NO_ELIGIBLE_DEVICE cause observed on
     * real hardware — then creates + starts the session, RETRYING transient
     * NO_ELIGIBLE with capped backoff (it is transient: the user's manual
     * connection-page reload made it succeed). Non-fatal throughout: on give-up
     * we stay Active via reachability (audio-only unaffected) and a capture can
     * re-attempt. Idempotent — also the re-mount recovery entry point (Gap 2).
     */
    func ensureCaptureSessionSelfHeal(deviceId: String?) async 
    
    /**
     * Single source of truth for "the camera stream is PAUSED" (user temple-tap,
     * a hardware privacy gesture with no app-callable resume). The shell's ONE
     * camera gate reads this for every stream-needing primitive — photo, video,
     * and the core-bypassing live-frames arm — so all three decline identically
     * (CaptureError.StreamPaused) instead of each re-deriving paused-ness.
     */
    func isCameraPaused()  -> Bool
    
    func onAppLifecycleChanged(toState: AppLifecycleState) 
    
    func onAudioRecorded(requestId: String, recording: AudioRecording?, error: BridgeError?) 
    
    func onAudioRouteChanged(newRoute: AudioRoute, reason: AudioRouteChangeReason) 
    
    func onCallStateChanged(state: CallState, phoneNumber: String?) 
    
    /**
     * Driven by the bridge's device-reachability observer (Android:
     * `Wearables.devices`, an observable `StateFlow`). Reports whether a
     * wearable is currently connected/available, independent of any MWDAT
     * DeviceSession — so an audio-only assistant (BT-SCO, no DeviceSession)
     * reflects a real "Connected" state instead of sitting at `Registered`.
     * A live DeviceSession takes precedence (see `apply_reachability`). (#9)
     */
    func onDeviceReachabilityChanged(device: DeviceInfo?) 
    
    func onDeviceSessionCreated(requestId: String, info: DeviceInfo?, error: DeviceSessionError?) 
    
    func onDeviceSessionStarted(requestId: String, error: DeviceSessionError?) 
    
    /**
     * Driven by the bridge's device-state observer. The shell normalizes
     * platform-specific state vocabularies onto the [`DeviceState`] enum
     * (R1) before calling this; the core dedups and emits `GlassesState`.
     */
    func onDeviceStateChanged(state: DeviceState) 
    
    func onHingesClosed() 
    
    func onPhoneNotification(packageName: String, title: String?, body: String?) 
    
    func onPhotoCaptured(requestId: String, photo: CapturedPhoto?, error: BridgeError?) 
    
    func onRegistrationResult(requestId: String, outcome: RegistrationOutcome) 
    
    func onSdkInitResult(requestId: String, error: BridgeError?) 
    
    func onSpeakCompleted(requestId: String, error: BridgeError?) 
    
    func onStreamOpened(requestId: String, error: BridgeError?) 
    
    /**
     * Stream-state observer. Tracks whether the camera stream is live
     * (`Streaming`) so `capture_photo` can decide its mode: live stream → grab a
     * frame off the feed; cold stream → open + discrete full-res capture. Any
     * non-`Streaming` state (incl. `Paused` — channel held, no frames — and the
     * frame-stall watchdog reaping the session to `Closed`) drops `stream_live`,
     * so the next photo correctly re-opens cold.
     *
     * `Closed` additionally surfaces as a transport error (hoisted from the
     * Kotlin bridge 2026-07-03): recovery rides the normal flow — the next
     * capture re-arms a fresh stream via the cold path. Deliberately NO
     * proactive re-arm loop here; that churned the BT link.
     */
    func onStreamStateChanged(state: StreamState) 
    
    func onSttStarted(requestId: String, error: BridgeError?) 
    
    func onThermalAlert(severity: ThermalSeverity) 
    
    /**
     * Inbound transcript from the bridge. Fans out to every registered
     * transcription sink + emits a `TranscriptEmitted` event (preserves
     * today's Android `RealMetaTransport` behaviour).
     */
    func onTranscript(source: TranscriptSource, transcript: Transcript) 
    
    /**
     * Stream-side transport error (e.g. SDK-level disconnect, permission
     * denied mid-stream). Emitted unchanged on the events stream.
     */
    func onTransportError(error: TransportError) 
    
    func onVideoCaptured(requestId: String, video: CapturedVideo?, error: BridgeError?) 
    
    func recordAudio(maxDurationSeconds: Int32?, silenceTimeoutSeconds: Double?, quality: AudioQuality) async  -> RealMetaRecordAudioResult
    
    func shutdown() async 
    
    func speak(text: String, voice: String?, rate: Double, pitch: Double, volume: Double, waitForCompletion: Bool) async  -> RealMetaSpeakResult
    
    /**
     * Register a transcription sink + start the bridge's STT session.
     * Returns the stream id for `stop_transcription_stream`.
     */
    func startTranscriptionStream(language: String, partial: Bool, sink: TranscriptSink)  -> String
    
    func stopTranscriptionStream(streamId: String) 
    
}

