public protocol RealtimeVoiceCoreProtocol : AnyObject {
    
    func appendHistory(turn: RealtimeTurn) 
    
    /**
     * The shell's summarize / custom-compact attempt FAILED — clear the
     * in-flight compaction so the next trigger retries (a single failure
     * must not wedge compaction for the rest of the session).
     */
    func cancelCompaction() 
    
    func cancelSpeak() 
    
    func clearHistory() 
    
    /**
     * Wake: open the WS, send `session.update`, await `session.updated`, then
     * memory/replay/glasses-state + `SessionStarted`. `None` on success,
     * `Some(error)` on failure. The shell's bridge opens the socket with the
     * gateway auth headers; the core owns the protocol sequence.
     */
    func connect(replay: Bool) async  -> String?
    
    func conversationHistory(limit: UInt32)  -> [RealtimeTurn]
    
    /**
     * Sleep: close the WS. History is preserved for the next wake; protocol-
     * specific session state that must NOT survive a sleep (Gemini's
     * resumption handle) is dropped so the next wake is a fresh session.
     */
    func disconnect() 
    
    func greet(prompt: String?) 
    
    func includeImage(imageUrl: String, prompt: String?) 
    
    func injectSystemContext(text: String) 
    
    func injectUserTurn(text: String) 
    
    func onClosed() 
    
    /**
     * The WS dropped (the shell's bridge `onFailure`/`onClosed`) — kick the
     * reconnect supervisor (no-op when already disconnected/closing).
     */
    func onFailure() 
    
    /**
     * A mic chunk from the audio device — encode it to the protocol's audio
     * frame (may be empty: Gemini drops pre-ready chunks).
     */
    func onMicAudio(sampleRate: Int32, pcm: Data) 
    
    /**
     * The WS opened (the shell's bridge `onOpen`) — unblock `connect`.
     */
    func onOpen() 
    
    /**
     * An inbound WS text frame (the shell's WS reader calls this synchronously,
     * preserving order). Mutate under the lock, drop, then perform effects.
     */
    func onText(text: String) 
    
    /**
     * Play the wake-confirmation chime through the audio sink. The shell calls
     * this at the Activating transition (gated on the glasses audio-link) so it
     * fills the connect-wait silence; it rides the same outgoing-audio path as
     * the greeting, which queues behind it (Finding A).
     */
    func playWakeSound() 
    
    func replaceHistory(turns: [RealtimeTurn]) 
    
    func say(text: String) 
    
    /**
     * Streaming video input (Gemini Live only, per-model gated). Non-video
     * sessions emit an `Error{kind: "video_input_unsupported"}` event instead
     * of silently dropping the frame.
     */
    func sendVideoFrame(frame: Data, mimeType: String) 
    
    func setMemoryPreamble(preamble: String?) 
    
    func setModel(model: String) 
    
    func setReasoningEffort(effortWire: String) 
    
    func setVoice(voice: String) 
    
    /**
     * Set a custom wake chime (decoded PCM16-LE mono at the active fidelity
     * rate), or clear it with empty `pcm` to fall back to the synth default. The
     * shell calls this at session start after fetching + decoding the dashboard
     * `wake_sound_url`.
     */
    func setWakeSound(sampleRate: Int32, pcm: Data) 
    
    /**
     * The shell finished summarizing (the `request_summary` callback) — apply it.
     */
    func submitCompacted(summaryText: String) 
    
    /**
     * The shell finished running a customer tool handler.
     */
    func submitToolResult(callId: String, name: String, output: String, isError: Bool, durationMs: Int64) 
    
    func updateInstructions(instructions: String) 
    
}

