/**
 * The stateful voice-command matcher / dispatcher. One per `glasses.voice`.
 */
public protocol VoiceCoreProtocol : AnyObject {
    
    /**
     * Remove a registration (the shell's `VoiceRegistration.cancel()`).
     */
    func cancelRegistration(id: String) 
    
    /**
     * The shell reports a handler finished (completed or cancelled). Clears
     * the hint's active state — `is_active` flips back to false.
     */
    func notifyHandlerFinished(id: String) 
    
    /**
     * Register a phrase. `has_handler` is true for `onPhrase` (the core will
     * emit dispatch intents for it) and false for `registerHint` (UI-only).
     * Returns the new hint's stable id.
     */
    func register(phrase: String, label: String?, stops: [String], hasHandler: Bool)  -> String
    
    /**
     * Manually bump a hint's fire stats (the customer's `reportFired`, for
     * hints whose matching they do themselves). No-op for an unknown id.
     */
    func reportFired(id: String, nowMs: Int64) 
    
    /**
     * Feed a transcript in. On a FINAL transcript the core matches it against
     * every registered phrase (case-insensitive substring) and against the
     * `stops` of every already-running handler, then emits the resulting
     * dispatch intents. Partials are ignored.
     */
    func submitTranscript(isFinal: Bool, text: String, nowMs: Int64) 
    
}

