/**
 * Plain-data construction parameters (the callback interfaces pass separately).
 */
public struct RealtimeConfig {
    /**
     * HiFi (sim) → 24 kHz PCM playback; false (glasses) → 8 kHz µ-law decode.
     */
    public var outgoingHifi: Bool
    public var tools: [RealtimeToolDef]
    public var turnDetection: RealtimeTurnDetection
    public var historyCap: UInt32
    public var compactionPolicy: RealtimeCompactionPolicy
    public var withinSessionMemory: String?
    public var model: String?
    public var voice: String?
    public var instructions: String
    public var reasoningEffort: String
    public var memoryAsContextItem: Bool
    public var hasGlassesState: Bool
    /**
     * Add the built-in `get_device_info` tool by default (the on-demand replacement
     * for per-turn glasses-state injection). Only added when `has_glasses_state` is
     * also true. The app can set this false and register its own tool instead.
     */
    public var includeDeviceInfoTool: Bool
    /**
     * Override for the default device-info system-prompt note: `None` → built-in,
     * `Some(text)` → that text, `Some("")` → omit the note.
     */
    public var deviceInfoNote: String?
    /**
     * Auto-sleep after this many ms of genuine conversational silence — no user speech,
     * no active response, and no assistant audio still playing. `None` or `<= 0` disables
     * it. The watcher lives in the core; the activity it measures is tracked in
     * `RealtimeState` from the realtime frames (so a long monologue is never cut off).
     */
    public var silenceTimeoutMs: Int64?
    /**
     * Base realtime WS URL (gateway relay); the core appends `?model=…` and the
     * shell's bridge adds the gateway auth headers.
     */
    public var baseWsUrl: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(
        /**
         * HiFi (sim) → 24 kHz PCM playback; false (glasses) → 8 kHz µ-law decode.
         */outgoingHifi: Bool, tools: [RealtimeToolDef], turnDetection: RealtimeTurnDetection, historyCap: UInt32, compactionPolicy: RealtimeCompactionPolicy, withinSessionMemory: String?, model: String?, voice: String?, instructions: String, reasoningEffort: String, memoryAsContextItem: Bool, hasGlassesState: Bool, 
        /**
         * Add the built-in `get_device_info` tool by default (the on-demand replacement
         * for per-turn glasses-state injection). Only added when `has_glasses_state` is
         * also true. The app can set this false and register its own tool instead.
         */includeDeviceInfoTool: Bool, 
        /**
         * Override for the default device-info system-prompt note: `None` → built-in,
         * `Some(text)` → that text, `Some("")` → omit the note.
         */deviceInfoNote: String?, 
        /**
         * Auto-sleep after this many ms of genuine conversational silence — no user speech,
         * no active response, and no assistant audio still playing. `None` or `<= 0` disables
         * it. The watcher lives in the core; the activity it measures is tracked in
         * `RealtimeState` from the realtime frames (so a long monologue is never cut off).
         */silenceTimeoutMs: Int64?, 
        /**
         * Base realtime WS URL (gateway relay); the core appends `?model=…` and the
         * shell's bridge adds the gateway auth headers.
         */baseWsUrl: String) {
        self.outgoingHifi = outgoingHifi
        self.tools = tools
        self.turnDetection = turnDetection
        self.historyCap = historyCap
        self.compactionPolicy = compactionPolicy
        self.withinSessionMemory = withinSessionMemory
        self.model = model
        self.voice = voice
        self.instructions = instructions
        self.reasoningEffort = reasoningEffort
        self.memoryAsContextItem = memoryAsContextItem
        self.hasGlassesState = hasGlassesState
        self.includeDeviceInfoTool = includeDeviceInfoTool
        self.deviceInfoNote = deviceInfoNote
        self.silenceTimeoutMs = silenceTimeoutMs
        self.baseWsUrl = baseWsUrl
    }
}



