// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * The sub-state of a connected (`Active`) glasses connection. Carries **no**
 * `ConnectionScope` — that interface is deleted (decision 1: it was dead code).
 */

public enum ActiveState {
    
    case connected(device: DeviceInfo, 
        /**
         * Camera usability within Connected — three DISTINCT truths the UI
         * must render differently (the old single `capture_ready` bool
         * conflated them; amber-banner decision 2026-07-16). `Ready` also
         * covers reachability-only Connected with no failure on record:
         * a capture self-arms the session on demand.
         */camera: CameraStatus
    )
    case sessionActive(device: DeviceInfo, session: SessionPhase
    )
    case streamActive(device: DeviceInfo, stream: StreamConfig
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeActiveState: FfiConverterRustBuffer {
    typealias SwiftType = ActiveState

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ActiveState {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .connected(device: try FfiConverterTypeDeviceInfo.read(from: &buf), camera: try FfiConverterTypeCameraStatus.read(from: &buf)
        )
        
        case 2: return .sessionActive(device: try FfiConverterTypeDeviceInfo.read(from: &buf), session: try FfiConverterTypeSessionPhase.read(from: &buf)
        )
        
        case 3: return .streamActive(device: try FfiConverterTypeDeviceInfo.read(from: &buf), stream: try FfiConverterTypeStreamConfig.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ActiveState, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .connected(device,camera):
            writeInt(&buf, Int32(1))
            FfiConverterTypeDeviceInfo.write(device, into: &buf)
            FfiConverterTypeCameraStatus.write(camera, into: &buf)
            
        
        case let .sessionActive(device,session):
            writeInt(&buf, Int32(2))
            FfiConverterTypeDeviceInfo.write(device, into: &buf)
            FfiConverterTypeSessionPhase.write(session, into: &buf)
            
        
        case let .streamActive(device,stream):
            writeInt(&buf, Int32(3))
            FfiConverterTypeDeviceInfo.write(device, into: &buf)
            FfiConverterTypeStreamConfig.write(stream, into: &buf)
            
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeActiveState_lift(_ buf: RustBuffer) throws -> ActiveState {
    return try FfiConverterTypeActiveState.lift(buf)
}

