/**
 * Why a `connect()` attempt failed. Migrated 1:1 from the hand-written
 * `ConnectError` in both libraries — same variants, with `TransportFailure`
 * redesigned to cross the FFI.
 */

public enum ConnectError {
    
    /**
     * No paired or otherwise known device is available to connect to.
     */
    case noDeviceAvailable
    /**
     * A runtime permission required to connect was denied.
     */
    case permissionDenied
    /**
     * Pairing / handshake with the device failed.
     */
    case pairingFailed
    /**
     * The install must register / authenticate before it can connect.
     */
    case registrationRequired
    /**
     * A native transport-layer failure surfaced while connecting.
     *
     * Was `TransportFailure(underlying: Throwable)`; redesigned to structured
     * `code` + `message` so it can cross the FFI (§ 3b). `code` is a stable
     * machine-readable tag the shell assigns when it catches the native
     * exception; `message` is the human-readable detail.
     */
    case transportFailure(code: String, message: String
    )
}


