// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.
/**
 * One node in a display tree. `sendContent` / `send` presents a single root
 * per call and replaces the whole display, so a [`DisplayNode`] tree is the
 * complete content of one frame (typically rooted at a [`DisplayNode::FlexBox`]).
 *
 * Some fine layout knobs Meta exposes (per-component width/height hints) are
 * intentionally omitted in v1 — the transport applies sensible defaults — and
 * can be added later without changing the node set.
 */

public enum DisplayNode {
    
    /**
     * Layout container. Maps to Meta `flexBox(direction, alignment, …) { … }`.
     */
    case flexBox(direction: Direction, 
        /**
         * Alignment along the main axis (justify-content).
         */mainAlign: Alignment, 
        /**
         * Alignment along the cross axis (align-items).
         */crossAlign: Alignment, 
        /**
         * Gap between children, in display units.
         */gap: UInt32, padding: EdgeInsets, background: Background, 
        /**
         * `Some(id)` if the whole container is tappable; the native layer
         * dispatches `id → onClick`.
         */onClick: String?, children: [DisplayNode]
    )
    /**
     * A run of text. Maps to Meta `text(…)`.
     */
    case text(text: String, style: TextStyle, color: TextColor, align: Alignment
    )
    /**
     * An image referenced by URL. Maps to Meta `image(url, …)`. There is no
     * vector/canvas — app visuals are pre-rendered and hosted at a URL the
     * glasses can fetch.
     */
    case image(url: String, size: ImageSize, cornerRadius: CornerRadius, align: Alignment
    )
    /**
     * A tappable button. Maps to Meta `button(text, …) { onClick }`.
     */
    case button(
        /**
         * Stable id for `onClick` dispatch (real tap or sim-injected select).
         */id: String, text: String, style: ButtonStyle, 
        /**
         * Optional leading icon name (see the module note on icon strings).
         */icon: String?, align: Alignment
    )
    /**
     * A standalone icon. Maps to Meta `icon(name, style, …)`.
     */
    case icon(
        /**
         * Vendor-specific icon name; validated by the transport.
         */name: String, style: IconStyle, align: Alignment
    )
    /**
     * An MP4 video by URL. Maps to Meta `VideoPlayer(VideoSource.Url, MP4)`.
     */
    case video(url: String
    )
}


