 * Events the runtime emits to the customer's observer (the FFI projection of the
 * internal `AssistantEventOut`; tool args cross as a JSON string).
 */

public enum RealtimeEvent {
    
    case userSpoke(transcript: String
    )
    case assistantSpoke(transcript: String
    )
    case toolCalled(name: String, argsJson: String, callId: String
    )
    case toolResult(callId: String, name: String, output: String, isError: Bool, durationMs: Int64
    )
    case error(kind: String, message: String
    )
    /**
     * First open completed — `session.update` accepted.
     */
    case sessionStarted(model: String, voice: String
    )
    /**
     * A reconnect cycle completed (the watchdog/failure-recovery path).
     */
    case reconnected(reason: String, downtimeMs: Int64
    )
    /**
     * The session ended (reconnect gave up, or a hard error).
     */
    case sessionEnded(reason: String, message: String?
    )
    /**
     * `sleepAfterSilence` reached — the conversation was genuinely idle (no user
     * speech, no active response, no assistant audio still playing) for the configured
     * timeout. The shell sleeps the assistant in response.
     */
    case silenceTimeout
}


