    )
    case timeout
    case hardwareUnavailable(reason: String
    )
    case platformError(code: String, message: String
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeTransportError: FfiConverterRustBuffer {
