    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> TransportError {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .websocketClosed(code: try FfiConverterInt32.read(from: &buf), reason: try FfiConverterOptionString.read(from: &buf)
        )
        
        case 2: return .handshakeFailed(reason: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .schemaMismatch(serverVersion: try FfiConverterString.read(from: &buf), clientVersion: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .timeout
        
        case 5: return .hardwareUnavailable(reason: try FfiConverterString.read(from: &buf)
        )
        
        case 6: return .platformError(code: try FfiConverterString.read(from: &buf), message: try FfiConverterString.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: TransportError, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .websocketClosed(code,reason):
            writeInt(&buf, Int32(1))
            FfiConverterInt32.write(code, into: &buf)
            FfiConverterOptionString.write(reason, into: &buf)
            
        
        case let .handshakeFailed(reason):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .schemaMismatch(serverVersion,clientVersion):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(serverVersion, into: &buf)
            FfiConverterString.write(clientVersion, into: &buf)
            
        
