/**
 * Vendor-agnostic hardware bridge — the shell's MWDAT (or future vendor SDK)
 * integration sits behind this. Sync request methods (the bridge does any
 * async/SDK work internally and calls back via `RealMetaCore`'s sync
 * completion methods, mirroring the `WebSocketBridge` ⟷ `on_*` pattern).
 *
 * Each method that needs a result carries a `request_id` string — a fresh
 * UUID minted by the core. The bridge's completion callback echoes that id
 * so the core can resolve the matching pending op.
 */
public protocol HardwareBridge : AnyObject {
    
    func initSdk(requestId: String) 
    
    /**
     * Trigger registration. Shell decides how (Activity on Android,
     * URL-callback on iOS); the core only sees the `RegistrationOutcome`.
     */
    func startRegistration(requestId: String) 
    
    func createDeviceSession(requestId: String, deviceId: String?) 
    
    func startDeviceSession(requestId: String) 
    
    func stopDeviceSession() 
    
    func openStream(requestId: String, config: OpenStreamConfig) 
    
    func closeStream() 
    
    /**
     * Capture a single photo. `frame_grab` selects the mechanism (the core owns
     * the policy): `false` = a full-res discrete capture (the cold-start first
     * shot, after the core has opened the stream); `true` = grab a still off the
     * already-live stream (every shot after, while the stream stays live — avoids
     * a second discrete capture stalling the feed into the frame-stall watchdog).
     * The bridge waits for STREAMING before firing; the core does not duplicate
     * that gate here.
     */
    func capturePhoto(requestId: String, format: PhotoFormat, frameGrab: Bool) 
    
    /**
     * Record a video clip end-to-end. Per Phase-2b scope, the capture
     * session lives in the shell (max-duration / silence-timeout logic is
     * shell-side until Phase 2c). The bridge returns the final clip via
     * `on_video_captured`.
     */
    func captureVideo(requestId: String, config: VideoCaptureConfig) 
    
    /**
     * Abort the in-flight video capture (the bridge drains a partial result
     * if available, otherwise resolves with an error). Mirrors
     * `BrowserSimCore::abort_capture_video` semantics: a separate sync
     * trigger so a customer-side cancellation can drive abort+drain without
     * relying on Rust-future Drop running async cleanup.
     */
    func abortVideoCapture(requestId: String) 
    
    /**
     * Record a discrete audio clip — bridge handles the full session
     * (mic capture + exit conditions + transcript synthesis if applicable).
     */
    func recordAudio(requestId: String, config: AudioRecordConfigWire) 
    
    /**
     * Start a continuous STT session. Transcripts flow through
     * `RealMetaCore::on_transcript` (sync inbound). The bridge owns the
     * SDK-specific restart-on-error machinery for Phase 2b; the core's
     * restart state machine is a Phase-2c deliverable.
     */
    func startSttSession(requestId: String, config: SttConfigWire) 
    
    func stopSttSession() 
    
    /**
     * `wait_for_completion=false` returns immediately (the bridge fires
     * `on_speak_completed` anyway for symmetry but the core forwards `Ok`
     * to the customer without awaiting).
     */
    func speak(requestId: String, text: String, config: SpeakConfigWire) 
    
    func cancelSpeak() 
    
    func earcon(sound: EarconSound, volume: Float) 
    
    func startHardwareObservers() 
    
    func stopHardwareObservers() 
    
    func hasMicPermission()  -> Bool
    
}



